mapper.update:
UPDATE account
account_no = #{accountNo}, customer_no = #{customerNo}, account_type = #{accountType}, currency = #{currency}, balance = #{balance}, status = #{status},
WHERE id = #{id}

mapper.select:
SELECT * FROM account

    AND account_no LIKE CONCAT('%',#{accountNo},'%')
    AND customer_no = #{customerNo}
    AND account_type = #{accountType}
    AND currency = #{currency}
    AND status = #{status}

ORDER BY id DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM account

    AND account_no LIKE CONCAT('%',#{accountNo},'%')
    AND customer_no = #{customerNo}
    AND account_type = #{accountType}
    AND currency = #{currency}
    AND status = #{status}
